SELECT [NavisionEan-step0].[Cross-Reference No_] AS EANCode, Item.[Country of Origin Code] AS Espr1, Item.[Tariff No_], Item.[Net Weight], Item.[Gross Weight], Item.No_ AS Item, Item.[Model Item No_] AS Article, Item.[Description 2], Item.[Variable Code 01] AS Color, [Variable Code].Description AS ColorDesc, Item.[Variable Code 02] AS [Size], Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Sales_Purchase Status Code] AS Espr2, SalesLineTMP.[Customer NO_], SalesLineTMP.[Customer Name], SalesLineTMP.[Document NO_], Sum(SalesLineTMP.qty) AS TotalQuantity
FROM ((SalesLineTMP LEFT JOIN (Item LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]) ON SalesLineTMP.NO_ = Item.No_) LEFT JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) INNER JOIN [Purchase Header] ON SalesLineTMP.[Document NO_] = [Purchase Header].No_
WHERE (((Item.[Configurator Relation])=3) AND ((Item.[Advertising Material])=0))
GROUP BY [NavisionEan-step0].[Cross-Reference No_], Item.[Country of Origin Code], Item.[Tariff No_], Item.[Net Weight], Item.[Gross Weight], Item.No_, Item.[Model Item No_], Item.[Description 2], Item.[Variable Code 01], [Variable Code].Description, Item.[Variable Code 02], Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Sales_Purchase Status Code], SalesLineTMP.[Customer NO_], SalesLineTMP.[Customer Name], SalesLineTMP.[Document NO_];

